with open("instagram_comments.md", "w", encoding="utf-8") as f:
    f.write("# Commentaires Instagram - Méthode 1,80$\n\n")
    f.write("Voici la liste des 90 commentaires préparés pour la session, répartis par catégorie et respectant les règles d'authenticité, d'expertise terrain et du ton Heldonica.\n\n")

    for category, lines in comments.items():
        f.write(f"## {category}\n\n")
        for idx, line in enumerate(lines, 1):
            f.write(f"{idx}. {line}\n")
        f.write("\n")

print("File generated successfully.")
